          title={`Remove "${confirmRemove}"?`}
          subtitle="This will delete the key files and SSH config entry."
          onCancel={() => { setConfirmRemove(null); setDialogActive(false) }}
        >
          <Text>Press Enter to confirm or Esc to cancel.</Text>
        </Dialog>
      )}
    </Box>
  )
