  HostName github.com
  User git`
    const result = parseConfigSegments(input)
    expect(result[0]).toMatchObject({ kind: "host", host: "github.com", managed: true })
  })

  it("strips # sshx from host name", () => {
    const input = `Host my-alias  # sshx
  HostName github.com`
