  it("parses agent add and requires a key argument", () => {
    expect(parseCliArgs(["agent", "add", "id_work"])).toEqual({
      mode: "headless",
      command: {
        name: "agent",
        action: "add",
        key: "id_work",
      },
    })

    expect(() => parseCliArgs(["agent", "add"])).toThrow("Usage: sshx agent add <key>")
  })
})

