import React, { useState } from "react"
import { Box, CustomSelect, Spinner, Text, useInput, type SelectProps } from "@vancityayush/tui"
import { Header } from "../components/Header.js"
import { PROVIDER_KEYS, PROVIDERS, type ProviderKey } from "../../providers.js"
import { testConnection, type TestResult } from "../../commands/test.js"

type Props = {
  onBack: () => void
}

const PROVIDER_OPTIONS = PROVIDER_KEYS.map((key) => ({
  label: PROVIDERS[key].label,
  value: key,
  description: PROVIDERS[key].hostname,
}))

export function TestConnection({ onBack }: Props): React.ReactNode {
  const [selectedProvider, setSelectedProvider] = useState<ProviderKey>("github")
  const [result, setResult] = useState<TestResult | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [running, setRunning] = useState(false)

  useInput((input, key) => {
    if (key.escape) {
      onBack()
      return
    }
    if (!running && result && input === "r") {
      setResult(null)
      setError(null)
    }
  })

  async function run(provider: ProviderKey): Promise<void> {
    setSelectedProvider(provider)
    setRunning(true)
    setResult(null)
    setError(null)

    try {
      setResult(await testConnection(provider))
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
    } finally {
      setRunning(false)
    }
  }

  if (running) {
    return (
      <Box flexDirection="column">
        <Header subtitle={`Testing ${PROVIDERS[selectedProvider].label} connection`} />
        <Spinner label={`Running ssh -T against ${PROVIDERS[selectedProvider].hostname}…`} />
      </Box>
    )
  }

  return (
    <Box flexDirection="column">
      <Header subtitle="Test SSH connection" />

      {!result && !error && (
        <>
          <CustomSelect
            {...({
              options: PROVIDER_OPTIONS,
              defaultValue: selectedProvider,
              onChange: (value: ProviderKey) => {
                void run(value)
              },
              visibleOptionCount: 4,
            } satisfies SelectProps<ProviderKey>)}
          />
          <Box marginTop={1}>
            <Text dimColor>Choose a provider to run `ssh -T` · Esc back</Text>
          </Box>
        </>
      )}

      {error && (
        <>
          <Text color="red">{error}</Text>
          <Box marginTop={1}>
            <Text dimColor>r retry · Esc back</Text>
          </Box>
        </>
      )}

      {result && (
        <>
          <Text color={result.success ? "green" : "yellow"}>
            {result.success ? "Connection looks good." : "Connection failed or needs attention."}
          </Text>
          <Box marginTop={1}>
            <Text wrap="wrap">{result.output || "No output returned."}</Text>
          </Box>
          <Box marginTop={1}>
            <Text dimColor>r test another provider · Esc back</Text>
          </Box>
        </>
      )}
    </Box>
  )
}

import packageJson from "../package.json"
import React from "react"
import { render } from "@vancityayush/tui"
import { agentAdd, agentList, agentRemove } from "./commands/agent.js"
import { copy } from "./commands/copy.js"
import { list } from "./commands/list.js"
import { remove } from "./commands/remove.js"
import { readGitContext, setup } from "./commands/setup.js"
import { testConnection } from "./commands/test.js"
import { getHelpText, parseCliArgs, resolveSetupOptions } from "./cli-core.js"
import { App } from "./tui/App.js"

const PACKAGE_VERSION = packageJson.version ?? "0.0.0"

async function main(argv: string[]): Promise<void> {
  try {
    const invocation = parseCliArgs(argv)

    if (invocation.mode === "tui") {
      await render(<App />)
      return
    }

    switch (invocation.command.name) {
      case "help":
        console.log(getHelpText())
        return
      case "version":
        console.log(PACKAGE_VERSION)
        return
      case "setup": {
        const result = await setup(resolveSetupOptions(invocation.command.options, readGitContext()))
        console.log(`Key generated: ~/.ssh/${result.keyName}`)
        console.log(`Host configured: ${result.host}`)
        console.log(result.publicKey)
        if (!result.clipboardCopied) {
          console.error("Warning: could not copy the public key to the clipboard.")
        }
        if (!result.browserOpened) {
          console.error("Warning: could not open the provider SSH settings page.")
        }
        return
      }
      case "list": {
        const keys = await list()
        if (keys.length === 0) {
          console.log("No managed keys found.")
          return
        }
        for (const key of keys) {
          console.log(`${key.name}\t${key.host}\t${key.provider ?? "unknown"}`)
        }
        return
      }
      case "remove": {
        const result = await remove(invocation.command.key)
        console.log(`Removed ${invocation.command.key}`)
        if (result.removedHosts.length > 0) {
          console.log(`Removed hosts: ${result.removedHosts.join(", ")}`)
        }
        return
      }
      case "copy": {
        const result = await copy(invocation.command.key)
        if (result.copied) {
          console.error(`Copied ${invocation.command.key} public key to clipboard.`)
        }
        console.log(result.publicKey)
        return
      }
      case "test": {
        const result = await testConnection(invocation.command.provider)
        if (result.output) {
          console.log(result.output)
        }
        if (!result.success) {
          process.exitCode = 1
        }
        return
      }
      case "agent":
        switch (invocation.command.action) {
          case "list": {
            const keys = await agentList()
            if (keys.length === 0) {
              console.log("No keys loaded in ssh-agent.")
              return
            }
            for (const key of keys) {
              console.log(`${key.path}\t${key.fingerprint}\t${key.type}`)
            }
            return
          }
          case "add":
            await agentAdd(invocation.command.key!)
            console.log(`Added ${invocation.command.key} to ssh-agent`)
            return
          case "remove":
            await agentRemove(invocation.command.key!)
            console.log(`Removed ${invocation.command.key} from ssh-agent`)
            return
        }
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    console.error(message)
    process.exitCode = 1
  }
}

void main(process.argv.slice(2))

import React, { useEffect, useState } from "react"
import { basename } from "node:path"
import { Box, CustomSelect, ListItem, Spinner, Text, useInput, type SelectProps } from "@vancityayush/tui"
import { Header } from "../components/Header.js"
import { agentAdd, agentList, agentRemove, type AgentKey } from "../../commands/agent.js"
import { list, type ManagedKey } from "../../commands/list.js"

type Props = {
  onBack: () => void
}

type Mode = "list" | "add"

export function Agent({ onBack }: Props): React.ReactNode {
  const [mode, setMode] = useState<Mode>("list")
  const [keys, setKeys] = useState<AgentKey[]>([])
  const [managedKeys, setManagedKeys] = useState<ManagedKey[]>([])
  const [selectedIndex, setSelectedIndex] = useState(0)
  const [loading, setLoading] = useState(true)
  const [status, setStatus] = useState<string | null>(null)

  useEffect(() => {
    void refresh()
  }, [])

  useInput((input, key) => {
    if (key.escape) {
      if (mode === "add") {
        setMode("list")
        return
      }
      onBack()
      return
    }

    if (loading) return

    if (mode === "add") {
      return
    }

    if (key.upArrow) {
      setSelectedIndex((current) => Math.max(0, current - 1))
    }
    if (key.downArrow) {
      setSelectedIndex((current) => Math.min(keys.length - 1, current + 1))
    }
    if (input === "a") {
      setMode("add")
    }
    if (input === "r") {
      void refresh()
    }
    if ((input === "d" || key.delete) && keys[selectedIndex]) {
      void removeSelected(keys[selectedIndex])
    }
  })

  async function refresh(): Promise<void> {
    setLoading(true)
    try {
      const [agentKeys, availableManagedKeys] = await Promise.all([agentList(), list()])
      setKeys(agentKeys)
      setManagedKeys(availableManagedKeys)
      setSelectedIndex((current) => Math.min(current, Math.max(0, agentKeys.length - 1)))
      setStatus(null)
    } catch (err) {
      setStatus(err instanceof Error ? err.message : String(err))
    } finally {
      setLoading(false)
    }
  }

  async function addManagedKey(keyName: string): Promise<void> {
    try {
      await agentAdd(keyName)
      setStatus(`Added ${keyName} to ssh-agent`)
      setMode("list")
      await refresh()
    } catch (err) {
      setStatus(err instanceof Error ? err.message : String(err))
      setMode("list")
    }
  }

  async function removeSelected(key: AgentKey): Promise<void> {
    try {
      await agentRemove(basename(key.path))
      setStatus(`Removed ${basename(key.path)} from ssh-agent`)
      await refresh()
    } catch (err) {
      setStatus(err instanceof Error ? err.message : String(err))
    }
  }

  if (loading) {
    return (
      <Box flexDirection="column">
        <Header subtitle="SSH agent" />
        <Spinner label="Loading ssh-agent keys…" />
      </Box>
    )
  }

  if (mode === "add") {
    const options = managedKeys.map((key) => ({
      label: key.name,
      value: key.name,
      description: key.host,
    }))

    return (
      <Box flexDirection="column">
        <Header subtitle="Add managed key to ssh-agent" />
        {options.length > 0 ? (
          <CustomSelect
            {...({
              options,
              onChange: (value: string) => {
                void addManagedKey(value)
              },
              visibleOptionCount: Math.min(6, Math.max(1, options.length)),
            } satisfies SelectProps<string>)}
          />
        ) : (
          <Text dimColor>No managed sshx keys available. Run setup first.</Text>
        )}
        <Box marginTop={1}>
          <Text dimColor>Esc back</Text>
        </Box>
      </Box>
    )
  }

  return (
    <Box flexDirection="column">
      <Header subtitle={`${keys.length} key${keys.length !== 1 ? "s" : ""} in ssh-agent`} />

      {keys.length === 0 && (
        <Text dimColor>No keys currently loaded in ssh-agent.</Text>
      )}

      {keys.map((key, index) => (
        <ListItem
          key={`${key.fingerprint}-${key.path}`}
          isFocused={index === selectedIndex}
          isSelected={index === selectedIndex}
          description={`${key.type} · ${key.fingerprint}`}
        >
          {key.path}
        </ListItem>
      ))}

      {status && (
        <Box marginTop={1}>
          <Text dimColor>{status}</Text>
        </Box>
      )}

      <Box marginTop={1}>
        <Text dimColor>a add managed key · d remove selected key · r refresh · Esc back</Text>
      </Box>
    </Box>
  )
}

import React, { useState } from "react"
import { useApp, useInput } from "@vancityayush/tui"
import { MainMenu, type MainMenuAction } from "./screens/MainMenu.js"
import { Setup } from "./screens/Setup.js"
import { KeyList } from "./screens/KeyList.js"
import { TestConnection } from "./screens/TestConnection.js"
import { Agent } from "./screens/Agent.js"
import { screenForMenuAction, type AppScreen } from "./navigation.js"

export function App(): React.ReactNode {
  const { exit } = useApp()
  const [screen, setScreen] = useState<AppScreen>("main-menu")

  useInput((input, key) => {
    if (screen !== "main-menu") return
    if (input === "q" || key.escape) {
      exit()
    }
  })

  const handleSelect = (action: MainMenuAction) => {
    setScreen(screenForMenuAction(action))
  }

  switch (screen) {
    case "setup":
      return <Setup onBack={() => setScreen("main-menu")} />
    case "key-list":
      return <KeyList onBack={() => setScreen("main-menu")} />
    case "test-connection":
      return <TestConnection onBack={() => setScreen("main-menu")} />
    case "agent":
      return <Agent onBack={() => setScreen("main-menu")} />
    case "main-menu":
    default:
      return <MainMenu onSelect={handleSelect} />
  }
}

import type { MainMenuAction } from "./screens/MainMenu.js"

export type AppScreen = "main-menu" | "setup" | "key-list" | "test-connection" | "agent"

export function screenForMenuAction(action: MainMenuAction): AppScreen {
  return action
}

